// ─── MASTER CATALOGUE ─────────────────────────────────────────────────────
const REGIONAL_CATALOGUES: Record<string, RegionCatalogue> = {
  west_africa: WEST_AFRICA,
  east_africa: EAST_AFRICA,
  southern_africa: SOUTHERN_AFRICA,
  north_africa: NORTH_AFRICA,
  caribbean: CARIBBEAN,
  latin_america: LATIN_AMERICA,
  middle_east: MIDDLE_EAST,
  south_asia: SOUTH_ASIA,
  southeast_asia: SOUTHEAST_ASIA,
  uk_europe: UK_EUROPE,
  north_america: NORTH_AMERICA,
}

/**
 * Get sample products for a category and country.
 * Returns region-specific products with correct local pricing.
 * Falls back to west_africa (Nigeria) if region not found.
 */
export function getSampleProducts(category: string, countryCode?: string | null): SampleProduct[] {
  const region = COUNTRY_REGION[countryCode || 'NG'] || 'west_africa'
  const catalogue = REGIONAL_CATALOGUES[region] || REGIONAL_CATALOGUES['west_africa']
  return catalogue[category] || catalogue['other'] || WEST_AFRICA['other']!
}

// Legacy export for backward compatibility
export const SAMPLE_PRODUCTS = WEST_AFRICA
